    },
    {
        heading: "Proven Results",
        paragraph: "Average 25-35% cost reduction with 3-6 month ROI"
    }, 
    {
        heading: "Predictable Pricing",
        paragraph: "No percentage of cloud spend - just transparent monthly fees"
    },
    {
        heading: "Fast ROI",
        para
    }

    
]

const Pricing = () => {
    return (
        <>
        <div>
        <div className="container">
            <h3>C3Ops Pricing Plans</h3>
            <h4>FinOps-Driven DevOps Platform + Expert Engineers</h4>
            <h6>Choose the plan that matches your organization's cloud spend and optimization needs</h6>
        </div>

        <div className="card-container">
            <h3>What Makes C3Ops Different</h3>
            <ul>
                <li>Enterprise-grade FinOps platform (CMDB, Budget Tracking, Cost Dashboards)</li>
                <li>Hands-on implementation, not just recommendations</li>
            </ul>
            <ul>
                <li>Dedicated FinOps Certified Engineer working with your team</li>
                <li>Proven 3-phase approach: Assess → Optimize → Govern</li>
            </ul>
        </div>
        </div>
        </>
    )

}

export default Pricing;
